import{_ as s,o as t,c as r,a2 as a}from"./chunks/framework.Cuq8tsM6.js";const m=JSON.parse('{"title":"Logistique & Technique","description":"","frontmatter":{"title":"Logistique & Technique"},"headers":[],"relativePath":"docs/fr/faq/logistics-tech.md","filePath":"docs/fr/faq/logistics-tech.md"}'),i={name:"docs/fr/faq/logistics-tech.md"};function n(o,e,l,u,d,c){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="logistique-print-technique" tabindex="-1">Logistique, Print &amp; Technique <a class="header-anchor" href="#logistique-print-technique" aria-label="Permalink to &quot;Logistique, Print &amp; Technique&quot;">​</a></h1><h2 id="🚨-depannage-technique" tabindex="-1">🚨 Dépannage Technique <a class="header-anchor" href="#🚨-depannage-technique" aria-label="Permalink to &quot;🚨 Dépannage Technique&quot;">​</a></h2><h3 id="mon-qr-code-renvoie-vers-une-page-404" tabindex="-1">Mon QR Code renvoie vers une page 404 <a class="header-anchor" href="#mon-qr-code-renvoie-vers-une-page-404" aria-label="Permalink to &quot;Mon QR Code renvoie vers une page 404&quot;">​</a></h3><p><strong>Cause probable :</strong> L&#39;URL de destination configurée dans la plateforme est vide ou erronée.</p><p><strong>Solution :</strong></p><ol><li>Connectez-vous à <a href="https://app.getinside.media" target="_blank" rel="noreferrer">app.getinside.media</a>.</li><li>Allez dans la campagne concernée → onglet <em>Configuration</em>.</li><li>Vérifiez le champ <strong>&quot;URL de redirection&quot;</strong>.</li><li>Sauvegardez — la mise à jour est <strong>instantanée</strong> (pas besoin de réimprimer).</li></ol><h3 id="je-n-arrive-pas-a-booster-le-post-instagram" tabindex="-1">Je n&#39;arrive pas à booster le post Instagram <a class="header-anchor" href="#je-n-arrive-pas-a-booster-le-post-instagram" aria-label="Permalink to &quot;Je n&#39;arrive pas à booster le post Instagram&quot;">​</a></h3><p><strong>Cause :</strong> La case &quot;Autoriser le partenaire à booster&quot; n&#39;a pas été cochée lors de la publication.</p><p><strong>Solution :</strong></p><ol><li>Aller sur le post Instagram → 3 points → Modifier.</li><li>Vérifier que le label <strong>&quot;Partenariat rémunéré&quot;</strong> est actif.</li><li>Vérifier que l&#39;option <strong>&quot;Autoriser le partenaire de marque à booster&quot;</strong> est active.</li></ol><h3 id="l-image-de-ma-newsletter-ne-s-affiche-pas" tabindex="-1">L&#39;image de ma newsletter ne s&#39;affiche pas <a class="header-anchor" href="#l-image-de-ma-newsletter-ne-s-affiche-pas" aria-label="Permalink to &quot;L&#39;image de ma newsletter ne s&#39;affiche pas&quot;">​</a></h3><p><strong>Cause :</strong> Problème d&#39;hébergement ou de lien.</p><p>Vérifiez :</p><ul><li>Le lien de l&#39;image est-il en <code>https</code> ? (Obligatoire)</li><li>L&#39;image est-elle hébergée sur un serveur public ?</li><li>Avez-vous respecté le poids max (150 Ko) ?</li></ul><p><em>Test : ouvrez l&#39;URL de l&#39;image seule dans un navigateur privé. Si elle ne charge pas, le problème vient de l&#39;hébergement.</em></p><hr><h2 id="📦-gestion-logistique" tabindex="-1">📦 Gestion Logistique <a class="header-anchor" href="#📦-gestion-logistique" aria-label="Permalink to &quot;📦 Gestion Logistique&quot;">​</a></h2><h3 id="j-ai-recu-les-encarts-en-avance-—-puis-je-commencer" tabindex="-1">J&#39;ai reçu les encarts en avance — puis-je commencer ? <a class="header-anchor" href="#j-ai-recu-les-encarts-en-avance-—-puis-je-commencer" aria-label="Permalink to &quot;J&#39;ai reçu les encarts en avance — puis-je commencer ?&quot;">​</a></h3><p>Il faut impérativement le feu vert de l&#39;annonceur pour diffuser une campagne plus tôt que prévu. Cela peut poser problème si la landing page n&#39;est pas encore active ou si la campagne entre en concurrence avec une autre offre.</p><h3 id="les-flyers-sont-arrives-endommages" tabindex="-1">Les flyers sont arrivés endommagés <a class="header-anchor" href="#les-flyers-sont-arrives-endommages" aria-label="Permalink to &quot;Les flyers sont arrivés endommagés&quot;">​</a></h3><p><strong>Action immédiate requise (sous 24h) :</strong></p><ol><li>Prenez des photos claires des cartons abîmés.</li><li>Notez des réserves précises sur le bon de livraison (BL).</li><li>Envoyez le tout à <code>logistique@getinside.fr</code>.</li></ol><p>Ne distribuez pas les supports endommagés.</p><h3 id="ecart-de-stock-—-j-ai-recu-plus-ou-moins-de-flyers-que-prevu" tabindex="-1">Écart de stock — j&#39;ai reçu plus ou moins de flyers que prévu <a class="header-anchor" href="#ecart-de-stock-—-j-ai-recu-plus-ou-moins-de-flyers-que-prevu" aria-label="Permalink to &quot;Écart de stock — j&#39;ai reçu plus ou moins de flyers que prévu&quot;">​</a></h3><p><strong>Vous en avez reçu MOINS :</strong> signalez-le immédiatement à l&#39;annonceur et à getinside via la messagerie de la campagne.</p><p><strong>Vous en avez reçu PLUS (surplus) :</strong> c&#39;est normal. Ce surplus correspond à la tolérance de gâche encadrée par l&#39;Article 38 du Code des usages de l&#39;industrie graphique (UNIIC). Voir la section ci-dessous pour le détail.</p><hr><h2 id="📏-gestion-des-surplus-d-impression-tolerance-de-gache" tabindex="-1">📏 Gestion des Surplus d&#39;Impression (Tolérance de Gâche) <a class="header-anchor" href="#📏-gestion-des-surplus-d-impression-tolerance-de-gache" aria-label="Permalink to &quot;📏 Gestion des Surplus d&#39;Impression (Tolérance de Gâche)&quot;">​</a></h2><p>L&#39;impression industrielle génère des variations inévitables entre la quantité commandée et la quantité livrée. Ce n&#39;est pas une erreur — c&#39;est une norme de production codifiée.</p><div class="tip custom-block"><p class="custom-block-title">Article 38 — Code des usages de l&#39;industrie graphique (UNIIC)</p><p>L&#39;acheteur est <strong>tenu d&#39;accepter</strong> les écarts de livraison suivants, qui sont inhérents aux aléas de fabrication :</p></div><table tabindex="0"><thead><tr><th style="text-align:left;">Volume commandé (BAT)</th><th style="text-align:left;">Tolérance légale</th></tr></thead><tbody><tr><td style="text-align:left;">≤ 2 000 ex</td><td style="text-align:left;">± 10%</td></tr><tr><td style="text-align:left;">≤ 10 000 ex</td><td style="text-align:left;">± 8%</td></tr><tr><td style="text-align:left;">≤ 20 000 ex</td><td style="text-align:left;">± 6,5%</td></tr><tr><td style="text-align:left;">≤ 25 000 ex</td><td style="text-align:left;">± 5,5%</td></tr><tr><td style="text-align:left;">≤ 35 000 ex</td><td style="text-align:left;">± 4,5%</td></tr><tr><td style="text-align:left;">≤ 50 000 ex</td><td style="text-align:left;">± 3,5%</td></tr><tr><td style="text-align:left;">≤ 100 000 ex</td><td style="text-align:left;">± 2,5%</td></tr><tr><td style="text-align:left;">&gt; 100 000 ex</td><td style="text-align:left;">± 2%</td></tr></tbody></table><p><strong>Marche à suivre pour le surplus :</strong></p><ol><li>Écoulez le surplus si possible (budget inchangé, volume supplémentaire = bonus pour l&#39;annonceur).</li><li>Si l&#39;insertion est impossible (entrepôt plein, campagne terminée), orientez vers le recyclage.</li><li>Si l&#39;annonceur conteste : référencez l&#39;Article 38 UNIIC et votre bon de livraison.</li></ol><hr><h2 id="🚚-avarie-de-transport" tabindex="-1">🚚 Avarie de Transport <a class="header-anchor" href="#🚚-avarie-de-transport" aria-label="Permalink to &quot;🚚 Avarie de Transport&quot;">​</a></h2><h3 id="j-ai-recu-quelques-cartons-abimes-—-dois-je-bloquer-la-campagne" tabindex="-1">J&#39;ai reçu quelques cartons abîmés — dois-je bloquer la campagne ? <a class="header-anchor" href="#j-ai-recu-quelques-cartons-abimes-—-dois-je-bloquer-la-campagne" aria-label="Permalink to &quot;J&#39;ai reçu quelques cartons abîmés — dois-je bloquer la campagne ?&quot;">​</a></h3><p>Non, sauf si les dommages dépassent 1% du volume total.</p><p>Une <strong>avarie mineure</strong> (inférieure à 1% du volume livré) est considérée comme non-bloquante selon les standards logistiques du transport de marchandises. Dans ce cas :</p><ol><li>Prenez des photos claires des cartons abîmés.</li><li>Notez des réserves sur le bon de livraison (BL).</li><li>Isolez les supports endommagés.</li><li>Démarrez la distribution sur le reste du stock.</li><li>Envoyez les photos à <code>logistique@getinside.fr</code> pour dossier assurance si nécessaire.</li></ol><div class="warning custom-block"><p class="custom-block-title">Avarie majeure (&gt; 1% du volume)</p><p>Si les dommages dépassent 1% du volume ou si les supports sont non conformes au BAT validé, <strong>suspendez l&#39;insertion</strong> et contactez <code>logistique@getinside.fr</code> avant toute distribution.</p></div><hr><h2 id="🔒-donnees-rgpd" tabindex="-1">🔒 Données &amp; RGPD <a class="header-anchor" href="#🔒-donnees-rgpd" aria-label="Permalink to &quot;🔒 Données &amp; RGPD&quot;">​</a></h2><h3 id="un-annonceur-demande-les-adresses-des-destinataires-—-puis-je-les-communiquer" tabindex="-1">Un annonceur demande les adresses des destinataires — puis-je les communiquer ? <a class="header-anchor" href="#un-annonceur-demande-les-adresses-des-destinataires-—-puis-je-les-communiquer" aria-label="Permalink to &quot;Un annonceur demande les adresses des destinataires — puis-je les communiquer ?&quot;">​</a></h3><p><strong>Non.</strong> Cette demande n&#39;est pas autorisée, même si l&#39;annonceur insiste.</p><p>En Retail Media, les données clients sont un <strong>actif First Party</strong> qui appartient exclusivement au Distributeur (vous). Le transfert de fichier est juridiquement interdit sans un nouvel opt-in spécifique (RGPD).</p><p>getinside opère comme <strong>Tiers de Confiance</strong> : nous routons le message de l&#39;annonceur vers votre audience, mais la donnée ne quitte jamais votre environnement sécurisé.</p><p>Si un annonceur vous fait cette demande, dirigez-le vers notre équipe : <a href="mailto:support@getinside.fr" target="_blank" rel="noreferrer">support@getinside.fr</a>.</p><h3 id="standards-rse-et-impression" tabindex="-1">Standards RSE et Impression <a class="header-anchor" href="#standards-rse-et-impression" aria-label="Permalink to &quot;Standards RSE et Impression&quot;">​</a></h3><p>Nos partenaires imprimeurs sont certifiés <strong>Imprim&#39;vert</strong>, ISO 9001/14001 et utilisent du papier FSC. L&#39;assemblage manuel (ex : échantillons) est réalisé par des <strong>Entreprises Adaptées (EA)</strong> favorisant l&#39;emploi de travailleurs handicapés.</p><h3 id="puis-je-utiliser-le-service-d-impression-pour-mes-propres-besoins" tabindex="-1">Puis-je utiliser le service d&#39;impression pour mes propres besoins ? <a class="header-anchor" href="#puis-je-utiliser-le-service-d-impression-pour-mes-propres-besoins" aria-label="Permalink to &quot;Puis-je utiliser le service d&#39;impression pour mes propres besoins ?&quot;">​</a></h3><p>Oui. En tant que centrale d&#39;achat, nous faisons bénéficier tous nos membres de tarifs négociés — pour de l&#39;auto-promotion ou des besoins internes.</p><hr><h2 id="🎨-creation-tracking" tabindex="-1">🎨 Création &amp; Tracking <a class="header-anchor" href="#🎨-creation-tracking" aria-label="Permalink to &quot;🎨 Création &amp; Tracking&quot;">​</a></h2><h3 id="est-ce-que-getinside-peut-creer-mes-visuels" tabindex="-1">Est-ce que getinside peut créer mes visuels ? <a class="header-anchor" href="#est-ce-que-getinside-peut-creer-mes-visuels" aria-label="Permalink to &quot;Est-ce que getinside peut créer mes visuels ?&quot;">​</a></h3><p>Oui. Notre <strong>Studio Créatif</strong> peut réaliser vos flyers, emails ou bannières pour un forfait de <strong>550€ HT</strong> par campagne.</p><h3 id="comment-tracker-les-ventes-roi" tabindex="-1">Comment tracker les ventes (ROI) ? <a class="header-anchor" href="#comment-tracker-les-ventes-roi" aria-label="Permalink to &quot;Comment tracker les ventes (ROI) ?&quot;">​</a></h3><p>getinside ne place pas de pixel sur votre site. L&#39;attribution repose sur deux leviers :</p><ol><li><strong>Code Promo Unique :</strong> créez un code spécifique (ex : <code>MERCI20</code>).</li><li><strong>Liens UTM :</strong> configurez l&#39;URL de votre QR Code avec des paramètres UTM (ex : <code>utm_source=insertion-colis</code>) pour suivre le trafic dans Google Analytics.</li></ol>',58)])])}const g=s(i,[["render",n]]);export{m as __pageData,g as default};
